        let stVith = HexCoord(q: 7, r: 3)

        update(alliedSupply) {
            $0.controller = .allies
            $0.hasRoad = true
        }
        update(germanSupply) {
            $0.controller = .germany
            $0.hasRoad = true
        }
        update(bastogneFortress) {
            $0.baseTerrain = .fortress
            $0.controller = .allies
            $0.hasRoad = true
            $0.fortressName = "Bastogne Fortress"
