import Foundation

struct RulerDirectiveFactory {
    func directive(from input: PlayerDirectiveInput, ruler: GameAgent?) -> StrategicDirective {
        let text = input.playerText.trimmingCharacters(in: .whitespacesAndNewlines)
        let domain = inferredDomain(from: text)
        let kind = inferredKind(from: text, domain: domain)
        let targetObjectiveId = inferredObjectiveId(from: text)
        let title = titleForDirective(text: text, kind: kind)

        return StrategicDirective(
            id: "player_directive_\(input.faction.rawValue)_turn_\(input.createdTurn)_\(abs(text.hashValue))",
            faction: input.faction,
            issuedByAgentId: ruler?.id ?? "\(input.faction.rawValue)_player_ruler",
            issuedByRole: .ruler,
            domain: domain,
            kind: kind,
            title: title,
            summary: text.isEmpty ? "Player issued an empty strategic directive." : text,
            targetRegionId: nil,
            targetObjectiveId: targetObjectiveId,
            targetAgentId: input.targetAgentId,
            urgency: inferredUrgency(from: text),
            status: .proposed,
            rationale: "Player-issued national directive.",
            createdTurn: input.createdTurn,
            expiresOnTurn: input.createdTurn + 3,
            sourceJSON: nil
        )
    }

    private func inferredDomain(from text: String) -> DirectiveDomain {
        let lower = text.lowercased()
        if lower.contains("production") || lower.contains("生产") || lower.contains("工厂") || lower.contains("装备") {
            return .production
        }
        if lower.contains("research") || lower.contains("tech") || lower.contains("科技") {
            return .research
        }
        if lower.contains("diplomacy") || lower.contains("外交") || lower.contains("停战") {
            return .diplomacy
        }
        if lower.contains("intelligence") || lower.contains("情报") || lower.contains("侦察") {
            return .intelligence
        }
        if lower.contains("supply") || lower.contains("补给") || lower.contains("休整") || lower.contains("补员") {
            return .logistics
        }
        return .operations
    }

    private func inferredKind(from text: String, domain: DirectiveDomain) -> DirectiveKind {
        let lower = text.lowercased()
        switch domain {
        case .production:
            return .productionPriority
        case .research:
            return .researchPriority
        case .diplomacy:
            return .diplomaticRisk
        case .intelligence:
            return .threatAssessment
        case .logistics:
            return .improveSupply
        default:
            if lower.contains("defend") || lower.contains("防守") || lower.contains("守住") {
                return .defendObjective
            }
            return .attackAxis
        }
    }

    private func inferredObjectiveId(from text: String) -> String? {
        let lower = text.lowercased()
        if lower.contains("bastogne") || lower.contains("巴斯托涅") {
            return "bastogne"
        }
        if lower.contains("st. vith") || lower.contains("圣维特") {
            return "st_vith"
        }
        if lower.contains("houffalize") || lower.contains("乌法利兹") {
            return "houffalize"
        }
        return nil
    }

    private func inferredUrgency(from text: String) -> DirectiveUrgency {
        let lower = text.lowercased()
        if lower.contains("critical") || lower.contains("立即") || lower.contains("马上") {
            return .critical
        }
        if lower.contains("high") || lower.contains("优先") || lower.contains("尽快") {
            return .high
        }
        return .normal
    }

    private func titleForDirective(text: String, kind: DirectiveKind) -> String {
        if text.isEmpty {
            return "Player strategic directive"
        }

        switch kind {
        case .attackAxis:
            return "Player attack directive"
        case .defendObjective:
            return "Player defense directive"
        case .productionPriority:
            return "Player production directive"
        case .researchPriority:
            return "Player research directive"
        case .diplomaticRisk:
            return "Player diplomacy directive"
        case .threatAssessment:
            return "Player intelligence directive"
        case .improveSupply:
            return "Player logistics directive"
        default:
            return "Player strategic directive"
        }
    }
}

import Foundation

struct ForceSummary: Codable, Equatable {
    let faction: Faction
    let totalDivisions: Int
    let armorDivisions: Int
    let artilleryDivisions: Int
    let averageHP: Int
    let averageOrganization: Int
    let supplied: Int
    let lowSupply: Int
    let encircled: Int
}

struct ObjectiveSummary: Codable, Equatable {
    let id: String
    let name: String
    let coord: HexCoord
    let controller: Faction?
    let type: ObjectiveType
}

struct FrontLineSummary: Codable, Equatable {
    let faction: Faction
    let contestedEdges: Int
    let friendlyControlledTiles: Int
    let enemyControlledTiles: Int
    let vulnerableObjectives: [String]
}

struct NationalContext: Codable, Equatable {
    let faction: Faction
    let turn: Int
    let maxTurns: Int
    let victorySummary: String
    let ownForces: ForceSummary
    let enemyForces: ForceSummary
    let objectives: [ObjectiveSummary]
    let frontLine: FrontLineSummary
    let activeDirectives: [String]
    let resourceStatus: String
    let threatSummary: String
}

struct MinisterContext: Codable, Equatable {
    let agentId: String
    let role: AgentRole
    let nationalContext: NationalContext
    let departmentFocus: String
    let facts: [String]
}

struct TheaterContext: Codable, Equatable {
    let faction: Faction
    let turn: Int
    let assignedDirectiveSummaries: [String]
    let frontLine: FrontLineSummary
    let availableDivisions: [String]
    let priorityObjectives: [ObjectiveSummary]
}

struct CommanderContext: Codable, Equatable {
    let agentId: String
    let faction: Faction
    let turn: Int
    let assignedDivisions: [Division]
    let nearbyKnownEnemies: [Division]
    let activeDirectives: [TheaterDirective]
}

enum AgentVisibilityState: String, Codable, Equatable {
    case visible
    case explored
    case unseen
}

struct TileSummary: Codable, Equatable {
    let coord: HexCoord
    let baseTerrain: BaseTerrain
    let hasRoad: Bool
    let controller: Faction?
    let cityName: String?
    let fortressName: String?
    let isPassable: Bool
    let visibility: AgentVisibilityState
}

struct DivisionSummary: Codable, Equatable {
    let id: String
    let name: String
    let faction: Faction
    let coord: HexCoord
    let hp: Int
    let maxHP: Int
    let organization: Int
    let supplyState: SupplyState
    let hasActed: Bool
    let movement: Int
    let range: Int
    let isArmor: Bool
    let isArtillery: Bool
}

struct SupplySummary: Codable, Equatable {
    let friendlySupplied: Int
    let friendlyLowSupply: Int
    let friendlyEncircled: Int
    let enemySupplied: Int
    let enemyLowSupply: Int
    let enemyEncircled: Int
}

struct EventSummary: Codable, Equatable {
    let turn: Int
    let faction: Faction?
    let phase: GamePhase?
    let message: String
}

struct AgentContext: Codable, Equatable {
    let agentId: String
    let faction: Faction
    let turn: Int
    let phase: GamePhase
    let personality: String
    let visibleTiles: [TileSummary]
    let friendlyDivisions: [DivisionSummary]
    let enemyDivisions: [DivisionSummary]
    let objectives: [ObjectiveSummary]
    let supplySummary: SupplySummary
    let recentEvents: [EventSummary]
    let playerDirective: String?
}

struct AgentContextBuilder {
    let maxFacts: Int
    let maxActiveDirectives: Int

    init(maxFacts: Int = 8, maxActiveDirectives: Int = 6) {
        self.maxFacts = maxFacts
        self.maxActiveDirectives = maxActiveDirectives
    }

    func nationalContext(for faction: Faction, state: GameState) -> NationalContext {
        let activeDirectiveSummaries = state.directiveBoard
            .approvedDirectives
            .filter { $0.faction == faction }
            .prefix(maxActiveDirectives)
            .map { "\($0.title): \($0.summary)" }

        return NationalContext(
            faction: faction,
            turn: state.turn,
            maxTurns: state.maxTurns,
            victorySummary: victorySummary(state.victoryState),
            ownForces: forceSummary(for: faction, state: state),
            enemyForces: forceSummary(for: faction.opponent, state: state),
            objectives: objectiveSummaries(state: state),
            frontLine: frontLineSummary(for: faction, state: state),
            activeDirectives: Array(activeDirectiveSummaries),
            resourceStatus: "V0.5 placeholder: resources and factories are advisory only.",
            threatSummary: threatSummary(for: faction, state: state)
        )
    }

    func ministerContext(for agent: GameAgent, state: GameState) -> MinisterContext {
        let national = nationalContext(for: agent.faction, state: state)
        return MinisterContext(
            agentId: agent.id,
            role: agent.role,
            nationalContext: national,
            departmentFocus: departmentFocus(for: agent.role),
            facts: Array(departmentFacts(for: agent.role, nationalContext: national).prefix(maxFacts))
        )
    }

    func theaterContext(for faction: Faction, state: GameState) -> TheaterContext {
        let directives = state.directiveBoard
            .theaterDirectives
            .filter { $0.faction == faction }
            .prefix(maxActiveDirectives)
            .map(\.summary)

        return TheaterContext(
            faction: faction,
            turn: state.turn,
            assignedDirectiveSummaries: Array(directives),
            frontLine: frontLineSummary(for: faction, state: state),
            availableDivisions: state.divisions.filter { $0.faction == faction }.map(\.name),
            priorityObjectives: objectiveSummaries(state: state).filter { $0.controller != faction }
        )
    }

    func commanderContext(for agent: GameAgent, state: GameState) -> CommanderContext {
        let assigned = state.divisions.filter { agent.assignedDivisionIds.contains($0.id) }
        let activeDirectives = state.directiveBoard
            .theaterDirectives
            .filter { $0.faction == agent.faction && ($0.targetAgentId == nil || $0.targetAgentId == agent.id) }

        return CommanderContext(
            agentId: agent.id,
            faction: agent.faction,
            turn: state.turn,
            assignedDivisions: assigned,
            nearbyKnownEnemies: nearbyEnemies(for: assigned, faction: agent.faction, state: state),
            activeDirectives: activeDirectives
        )
    }

    func agentContext(
        for agent: GameAgent,
        state: GameState,
        playerDirective: String?
    ) -> AgentContext {
        let assignedIds = Set(agent.assignedDivisionIds)
        let friendlyDivisions = state.divisions
            .filter { $0.faction == agent.faction && (assignedIds.isEmpty || assignedIds.contains($0.id)) }
            .map(divisionSummary)
            .sorted { $0.id < $1.id }
        let enemyDivisions = state.divisions
            .filter { $0.faction == agent.faction.opponent }
            .map(divisionSummary)
            .sorted { $0.id < $1.id }

        return AgentContext(
            agentId: agent.id,
            faction: agent.faction,
            turn: state.turn,
            phase: state.phase,
            personality: agent.personality.prompt,
            visibleTiles: tileSummaries(state: state),
            friendlyDivisions: friendlyDivisions,
            enemyDivisions: enemyDivisions,
            objectives: objectiveSummaries(state: state),
            supplySummary: supplySummary(for: agent.faction, state: state),
            recentEvents: recentEvents(state: state),
            playerDirective: playerDirective
        )
    }

    private func forceSummary(for faction: Faction, state: GameState) -> ForceSummary {
        let divisions = state.divisions.filter { $0.faction == faction }
        let totalHP = divisions.reduce(0) { $0 + $1.hp }
        let totalOrganization = divisions.reduce(0) { $0 + $1.organization }
        let divisor = max(1, divisions.count)

        return ForceSummary(
            faction: faction,
            totalDivisions: divisions.count,
            armorDivisions: divisions.filter(\.isArmor).count,
            artilleryDivisions: divisions.filter(\.isArtillery).count,
            averageHP: totalHP / divisor,
            averageOrganization: totalOrganization / divisor,
            supplied: divisions.filter { $0.supplyState == .supplied }.count,
            lowSupply: divisions.filter { $0.supplyState == .lowSupply }.count,
            encircled: divisions.filter { $0.supplyState == .encircled }.count
        )
    }

    private func objectiveSummaries(state: GameState) -> [ObjectiveSummary] {
        state.map.objectives.map { objective in
            ObjectiveSummary(
                id: objective.id,
                name: objective.name,
                coord: objective.coord,
                controller: state.map.tile(at: objective.coord)?.controller,
                type: objective.type
            )
        }
    }

    private func tileSummaries(state: GameState) -> [TileSummary] {
        state.map.tiles.values
            .sorted {
                if $0.coord.q != $1.coord.q {
                    return $0.coord.q < $1.coord.q
                }
                return $0.coord.r < $1.coord.r
            }
            .map { tile in
                TileSummary(
                    coord: tile.coord,
                    baseTerrain: tile.baseTerrain,
                    hasRoad: tile.hasRoad,
                    controller: tile.controller,
                    cityName: tile.cityName,
                    fortressName: tile.fortressName,
                    isPassable: tile.isPassable,
                    visibility: .visible
                )
            }
    }

    private func divisionSummary(_ division: Division) -> DivisionSummary {
        DivisionSummary(
            id: division.id,
            name: division.name,
            faction: division.faction,
            coord: division.coord,
            hp: division.hp,
            maxHP: division.maxHP,
            organization: division.organization,
            supplyState: division.supplyState,
            hasActed: division.hasActed,
            movement: division.movement,
            range: division.range,
            isArmor: division.isArmor,
            isArtillery: division.isArtillery
        )
    }

    private func supplySummary(for faction: Faction, state: GameState) -> SupplySummary {
        let friendly = state.divisions.filter { $0.faction == faction }
        let enemy = state.divisions.filter { $0.faction == faction.opponent }

        return SupplySummary(
            friendlySupplied: friendly.filter { $0.supplyState == .supplied }.count,
            friendlyLowSupply: friendly.filter { $0.supplyState == .lowSupply }.count,
            friendlyEncircled: friendly.filter { $0.supplyState == .encircled }.count,
            enemySupplied: enemy.filter { $0.supplyState == .supplied }.count,
            enemyLowSupply: enemy.filter { $0.supplyState == .lowSupply }.count,
            enemyEncircled: enemy.filter { $0.supplyState == .encircled }.count
        )
    }

    private func recentEvents(state: GameState) -> [EventSummary] {
        state.eventLog
            .suffix(maxFacts)
            .map { entry in
                EventSummary(
                    turn: entry.turn,
                    faction: entry.faction,
                    phase: entry.phase,
                    message: entry.message
                )
            }
    }

    private func frontLineSummary(for faction: Faction, state: GameState) -> FrontLineSummary {
        var contestedEdges = 0
        var vulnerableObjectives: [String] = []

        for tile in state.map.tiles.values where tile.controller == faction {
            for neighborCoord in tile.coord.neighbors {
                guard let neighbor = state.map.tile(at: neighborCoord), neighbor.controller == faction.opponent else {
                    continue
                }
                contestedEdges += 1
            }
        }

        for objective in state.map.objectives {
            guard let tile = state.map.tile(at: objective.coord), tile.controller == faction else {
                continue
            }

            let hasEnemyNeighbor = objective.coord.neighbors.contains {
                state.map.tile(at: $0)?.controller == faction.opponent
            }
            if hasEnemyNeighbor {
                vulnerableObjectives.append(objective.name)
            }
        }

        return FrontLineSummary(
            faction: faction,
            contestedEdges: contestedEdges,
            friendlyControlledTiles: state.map.tiles.values.filter { $0.controller == faction }.count,
            enemyControlledTiles: state.map.tiles.values.filter { $0.controller == faction.opponent }.count,
            vulnerableObjectives: vulnerableObjectives
        )
    }

    private func nearbyEnemies(for divisions: [Division], faction: Faction, state: GameState) -> [Division] {
        state.divisions
            .filter { enemy in
                enemy.faction == faction.opponent && divisions.contains { $0.coord.distance(to: enemy.coord) <= 4 }
            }
            .prefix(6)
            .map { $0 }
    }

    private func victorySummary(_ victoryState: VictoryState) -> String {
        if let winner = victoryState.winner {
            return "\(winner.displayName) victory: \(victoryState.reason?.rawValue ?? "resolved")."
        }
        return "Victory unresolved."
    }

    private func threatSummary(for faction: Faction, state: GameState) -> String {
        let enemy = forceSummary(for: faction.opponent, state: state)
        if enemy.armorDivisions >= 2 {
            return "Enemy armored concentration detected."
        }
        if enemy.artilleryDivisions > 0 {
            return "Enemy artillery can shape key objectives."
        }
        return "No decisive enemy concentration detected."
    }

    private func departmentFocus(for role: AgentRole) -> String {
        switch role {
        case .armamentsMinister:
            return "Production, factories, equipment losses, and future research priorities."
        case .armyMinister:
            return "Manpower, organization, replacement priorities, training, and command assignments."
        case .foreignMinister:
            return "Diplomatic risks, alliance posture, escalation, and negotiation options."
        case .intelligenceMinister:
            return "Enemy threats, unknowns, weak points, and risk warnings."
        case .ruler:
            return "National strategy and final prioritization."
        case .fieldMarshal:
            return "Theater-level front planning."
        case .armyCommander:
            return "Operational execution with assigned divisions."
        }
    }

    private func departmentFacts(for role: AgentRole, nationalContext: NationalContext) -> [String] {
        switch role {
        case .armamentsMinister:
            return [
                "Own divisions: \(nationalContext.ownForces.totalDivisions).",
                "Average HP: \(nationalContext.ownForces.averageHP).",
                "Armored divisions: \(nationalContext.ownForces.armorDivisions).",
                nationalContext.resourceStatus
            ]
        case .armyMinister:
            return [
                "Average organization: \(nationalContext.ownForces.averageOrganization).",
                "Low supply divisions: \(nationalContext.ownForces.lowSupply).",
                "Encircled divisions: \(nationalContext.ownForces.encircled).",
                "Enemy divisions: \(nationalContext.enemyForces.totalDivisions)."
            ]
        case .foreignMinister:
            return [
                "War remains active.",
                "No v0.5 diplomatic action mutates state.",
                "Objectives contested: \(nationalContext.objectives.filter { $0.controller != nationalContext.faction }.count)."
            ]
        case .intelligenceMinister:
            return [
                nationalContext.threatSummary,
                "Contested front edges: \(nationalContext.frontLine.contestedEdges).",
                "Vulnerable objectives: \(nationalContext.frontLine.vulnerableObjectives.joined(separator: ", "))."
            ]
        default:
            return [
                nationalContext.victorySummary,
                "Active directives: \(nationalContext.activeDirectives.count)."
            ]
        }
    }
}

