                    DataValidationError(
                        message: "Unit template \(template.id) component weights sum to \(componentWeight), expected 1.0."
                    )
                )
            }
        }

        let germanSupplySources = scenario.map.tiles.filter {
            $0.isSupplySource && $0.supplyFaction == "germany"
