            ScrollView {
                sidePanel
                    .padding(12)
            }
            .background(Color(.secondarySystemBackground))
            .frame(width: 350)
        }
    }

    private var compactLayout: some View {
        GeometryReader { proxy in
            let mapHeight = max(300, min(proxy.size.height * 0.52, 460))

            VStack(spacing: 0) {
