                }
            }
            .padding(.horizontal, 10)
            .padding(.bottom, 12)
        }
        .background(Color(.secondarySystemBackground))
    }
}

private enum CompactInfoPanel: String, CaseIterable, Identifiable {
    case unit = "Unit"
